#include <stdio.h>
#include <algorithm>
#include <queue>
#include <cstring>
using namespace std;

const int N=2e4+10;

struct Edge{
    int to,val;
};

bool operator<(Edge x,Edge y){
    return x.val>y.val;
}

int n,m,k,g,p[25],ones[1<<20],a[1<<20],id[1<<20];
int dis[N],d[25][25];
int f[2][20][190000],ans=1e9;
bool b[N];
vector<Edge> e[N];

void Solve(int st,int num){
    priority_queue<Edge> q;
    memset(dis,0x3f,sizeof(dis));
    memset(b,false,sizeof(b));
    dis[st]=0,q.push({st,0});
    while(q.size()){
        if(b[q.top().to]){
            q.pop();
            continue;
        }
        int x=q.top().to;
        q.pop(),b[x]=1;
        for(Edge y:e[x])
            if(dis[y.to]>dis[x]+y.val){
                dis[y.to]=dis[x]+y.val;
                q.push({y.to,dis[y.to]});
            }
    }
    for(int i=1;i<=k+1;i++)
        d[num][i]=dis[i];
    d[num][k+2]=dis[n];
}

bool cmp(int x,int y){
    if(ones[x]==ones[y])
    	return x<y;
    return ones[x]<ones[y];
}

void output(int x){
	for(int i=0;i<k;i++)
		printf("%d",((x>>i)&1));
	puts("");
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        e[u].push_back({v,w});
        e[v].push_back({u,w});
    }
    scanf("%d",&g);
    for(int i=1,r,s;i<=g;i++){
        scanf("%d%d",&r,&s);
        p[s]|=(1<<r-2);
    }
    for(int i=1;i<=k+1;i++)
        Solve(i,i);
    Solve(n,k+2);
    if(k==0){
    	printf("%d\n",d[1][2]);
    	return 0;
	}
    for(int i=1;i<1<<k;i++){
        a[i]=i;
        ones[i]=ones[i-(i&(-i))]+1;
    }
    sort(a+1,a+(1<<k),cmp);
    for(int i=1;i<1<<k;i++)
        id[a[i]]=i;
    memset(f,0x3f,sizeof(f));
    for(int i=1;i<=k;i++)
		if(!p[i+1]) 
        	f[0][i-1][i]=d[1][i+1];
    for(int i=0,r=0,xs=0;i+1<1<<k;i=r,xs^=1){
        memset(f[xs^1],0x3f,sizeof(f[xs^1]));
        while(ones[a[r+1]]<=ones[a[i]]+1 && r+1<1<<k)
            r++;
        for(int j=i+1,S;j<=r;j++){
            S=a[j];
            for(int w=0;w<k;w++){
                if(!((S>>w)&1))
                    continue;
                if(j+1==1<<k)
                    ans=min(ans,f[xs][w][j-i]+d[w+2][k+2]);
                for(int l=0;l<k;l++){
                    if(((S>>l)&1) || (p[l+2]&S)!=p[l+2])
                        continue;
                    f[xs^1][l][id[S|(1<<l)]-r]=min(f[xs^1][l][id[S|(1<<l)]-r],f[xs][w][j-i]+d[w+2][l+2]);
                }
            }
        }
    }
    printf("%d",ans); 
    return 0;
}
